string standalone.$FUNCTION_NAME$($PARAMS$)
{
    /*
     * Function Name: $FUNCTION_NAME$
     * Author: $USER$
     * Parameters:
     *     $PARAMS_DESC$
     *
     * Description: $DESCRIPTION$
     *
     * Info:#
     * 1. $STEP1$
     *
     * Return Sample:
     * {
     *     "status": "success",
     *     "data": {}
     * }
     */

    /* ========================== For Testing Start ========================== */
    // $TEST_CODE$
    /* =========================== For Testing End =========================== */

    // ===== Initialization =====
    function_name = "$FUNCTION_NAME$";
    log_type = "info";
    log_message = "";
    opt_data = "";

    try
    {
        // ===== Input Validation =====
        $VALIDATION$

        // ===== Business Logic =====
        $END$

        // ===== Build Success Response =====
        return {"status":"success","data":result_data};
    }
    catch (e)
    {
        // ===== Error Logging =====
        log_type = "error";
        log_message = e;
        standalone.developerLog(function_name,log_type,log_message,zoho.loginuserid,opt_data);
        return {"status":"error","message":e};
    }

    return "FAKE_RETURN_TO_SATISFY_DELUGE"; // Should never be reached
}

