map validation_rule.$FUNCTION_NAME$(String crmAPIRequest)
{
    /*
     * Function Name: $FUNCTION_NAME$
     * Description: $DESCRIPTION$
     * Returns: Map with status key (success/error)
     */

    entity_map = crmAPIRequest.toMap().get("record");
    response = Map();

    try
    {
        // ===== Input Validation =====
        $VALIDATION$

        // ===== Business Logic =====
        $END$

        // ===== On Success =====
        response.put('status','success');

        // ===== On Error (example) =====
        // response.put('status','error');
        // response.put('message', 'Validation error message (max 100 chars)');
    }
    catch (e)
    {
        response.put('status','error');
        response.put('message', 'Validation failed');
    }

    return response;
}

