string button.$FUNCTION_NAME$(String recordId)
{
    /*
     * Function Name: $FUNCTION_NAME$
     * Description: $DESCRIPTION$
     * Returns: Success/error message string
     */

    try
    {
        // ===== Input Validation =====
        if(isNull(recordId) || recordId == "")
        {
            return "Error: Record ID is required";
        }

        record_long = recordId.toLong();

        // ===== Business Logic =====
        $END$

        return "Success: $SUCCESS_MESSAGE$";
    }
    catch (e)
    {
        // ===== Error Logging =====
        function_name = "$FUNCTION_NAME$";
        standalone.developerLog(function_name,"error",e,zoho.loginuserid,"");
        return "Error: " + e;
    }

    return "";
}

string related_list.$FUNCTION_NAME$(Int recordId)
{
    /*
     * Function Name: $FUNCTION_NAME$
     * Description: $DESCRIPTION$
     * Returns: XML string
     */

    try
    {
        // ===== Input Validation =====
        if(isNull(recordId))
        {
            return "<error><message>Record ID is required</message></error>";
        }

        // ===== Business Logic =====
        $END$

        // ===== Build XML Response =====
        response_xml = "<record></record>";
        return response_xml;
    }
    catch (e)
    {
        // ===== Error Logging =====
        function_name = "$FUNCTION_NAME$";
        standalone.developerLog(function_name,"error",e,zoho.loginuserid,"");
        return "<error><message>An error occurred</message></error>";
    }

    return "";
}
